body:
Looks like Verilator is not handling nested fork with disable properly. This issue might be related to #6591 but I am not 100% sure. The following test case can be used to reproduce the behavior I am seeing.

```
module disable_fork (
    input  logic i_clk
);
time delay1 =  500ns; // min period
time delay2 = 3333ns; // max period

    logic clk_re = 1'b0; // rising edge of the clock
    logic [2:0] counter = 3'b000;
    always begin    
    fork
        begin: check1
            #delay1;
            #1 disable check2;
            fork
                begin: check3
                    #(delay2 - delay1);
                    clk_re <= 1'b0;
                    #1 disable check4;
                    if (counter == 3'b110) begin
                        $display("%0t slow clock detected  ", $time);
                    end
                    if (counter < 3'b111) begin
                        counter <= counter + 3'b001;
                    end
                end
                begin: check4
                    @(posedge i_clk);
                    clk_re <= 1'b1;
                    $display("%0t rising clk edge detected after delay1 expiration ", $time);
                    counter <= 3'b000;
                    #1 disable check3;
                end
            join 
        end

        begin: check2
            @(posedge i_clk);
            $display("%0t rising clk edge detected before delay1 expiration  ", $time);
            clk_re <= 1'b0;
            #1 disable check1;
            if (counter == 3'b110) $display("%0t fast clk detected", $time);
            if (counter < 3'b111) 
                counter <= counter + 3'b001;
        end
    join
    end 
endmodule
module disable_fork_tb  ;

logic clk;
integer code;

task clk_cycle(input time half_period);
    clk =1'b0;
    #half_period;
    clk =1'b1;
    #half_period;
endtask:clk_cycle

initial begin
    repeat (100) begin
       clk_cycle(200ns);
    end
    repeat (100) begin
       clk_cycle(5400ns);
    end
   $write("*-* All Finished *-*\n");
   $finish;
end // end initial begin

initial begin
    string trace_file;
    if ($test$plusargs("trace") != 0) begin
        if( $test$plusargs("trace_file")  ) begin
         code=$value$plusargs("trace_file=%s", trace_file);
        end else begin
            trace_file = "./vlt_dump.vcd";
        end
        $display("[%0t] Tracing to %s\n", $time, trace_file);
        $dumpfile(trace_file);
        $dumpvars();
    end
end // end initial begin


disable_fork a_inst(
                    .i_clk(clk)
                    );

endmodule

```


The output should be detecting both the low and high clock frequency. However Verilator only emmits the following output:
```
2000 rising clk edge detected before delay1 expiration
6000 rising clk edge detected after delay1 expiration
*-* All Finished *-*
```
